declare(strict_types=1);

namespace HtmlToMarkdown\Tests;

use PHPUnit\Framework\TestCase;

use function HtmlToMarkdown\convert;

class OptionsTest extends TestCase
{
    /**
     * Backticks code block style uses triple backtick fences
     */
    public function testOptionsCodeBlockBackticks(): void
    {
        $html = "<pre><code class=\"language-js\">console.log('hi');</code></pre>";
        $result = convert($html);
        $content = $result['content'] ?? '';

        $this->assertStringContainsString("```", $content);
        $this->assertStringContainsString("console.log('hi');", $content);
    }

    /**
     * Tildes code block style uses triple tilde fences
     */
    public function testOptionsCodeBlockTildes(): void
    {
        $html = "<pre><code>some code</code></pre>";
        $result = convert($html);
        $content = $result['content'] ?? '';

        $this->assertStringContainsString("~~~", $content);
        $this->assertStringContainsString("some code", $content);
    }

    /**
     * escape_asterisks option escapes asterisks in plain text
     */
    public function testOptionsEscapeAsterisks(): void
    {
        $html = "<p>Use 2*3 = 6 in math.</p>";
        $result = convert($html);
        $content = $result['content'] ?? '';

        $this->assertNotEmpty(trim($content), 'expected non-empty content');
        $this->assertStringContainsString("2", $content);
        $this->assertStringContainsString("3", $content);
        $this->assertStringContainsString("6", $content);
    }

    /**
     * escape_misc option escapes miscellaneous markdown characters
     */
    public function testOptionsEscapeMisc(): void
    {
        $html = "<p>Use # and | and ~ in text.</p>";
        $result = convert($html);
        $content = $result['content'] ?? '';

        $this->assertNotEmpty(trim($content), 'expected non-empty content');
        $this->assertStringContainsString("Use", $content);
        $this->assertStringContainsString("and", $content);
        $this->assertStringContainsString("in text.", $content);
    }

    /**
     * escape_underscores option escapes underscores in plain text
     */
    public function testOptionsEscapeUnderscores(): void
    {
        $html = "<p>The variable_name is defined.</p>";
        $result = convert($html);
        $content = $result['content'] ?? '';

        $this->assertNotEmpty(trim($content), 'expected non-empty content');
        $this->assertStringContainsString("variable", $content);
        $this->assertStringContainsString("name", $content);
        $this->assertStringContainsString("defined.", $content);
    }

    /**
     * ATX heading style produces hash-prefixed headings
     */
    public function testOptionsHeadingStyleAtx(): void
    {
        $html = "<h1>Title</h1><h2>Subtitle</h2>";
        $result = convert($html);
        $content = $result['content'] ?? '';

        $this->assertStringContainsString("# Title", $content);
        $this->assertStringContainsString("## Subtitle", $content);
    }

    /**
     * ATX closed heading style adds closing hashes
     */
    public function testOptionsHeadingStyleAtxClosed(): void
    {
        $html = "<h1>Closed Heading</h1>";
        $result = convert($html);
        $content = $result['content'] ?? '';

        $this->assertStringContainsString("# Closed Heading #", $content);
    }

    /**
     * Underlined heading style produces setext-style headings for h1 and h2
     */
    public function testOptionsHeadingStyleUnderlined(): void
    {
        $html = "<h1>Main Title</h1>";
        $result = convert($html);
        $content = $result['content'] ?? '';

        $this->assertNotEmpty(trim($content), 'expected non-empty content');
        $this->assertStringContainsString("Main Title", $content);
    }

    /**
     * Custom bullet character for unordered lists
     */
    public function testOptionsListCustomBullets(): void
    {
        $html = "<ul><li>Item A</li><li>Item B</li></ul>";
        $result = convert($html);
        $content = $result['content'] ?? '';

        $this->assertStringContainsString("* Item A", $content);
        $this->assertStringContainsString("* Item B", $content);
    }

