    public function testOptionsOutputFormatDjot(): void
    {
        $html = "<p>Simple paragraph.</p>";
        $result = convert($html);
        $content = $result['content'] ?? '';

        $this->assertNotEmpty(trim($content), 'expected non-empty content');
        $this->assertStringContainsString("Simple paragraph.", $content);
    }

    /**
     * Default markdown output format produces standard markdown
     */
    public function testOptionsOutputFormatMarkdown(): void
    {
        $html = "<h1>Title</h1><p>Some text.</p>";
        $result = convert($html);
        $content = $result['content'] ?? '';

        $this->assertStringContainsString("# Title", $content);
        $this->assertStringContainsString("Some text.", $content);
    }

    /**
     * Plain text output format strips markdown syntax
     */
    public function testOptionsOutputFormatPlain(): void
    {
        $html = "<h1>Title</h1><p>Some <strong>bold</strong> text.</p>";
        $result = convert($html);
        $content = $result['content'] ?? '';

        $this->assertStringContainsString("Title", $content);
        $this->assertStringContainsString("bold", $content);
        $this->assertStringContainsString("text.", $content);
        $this->assertStringNotContainsString("**bold**", $content);
        $this->assertStringNotContainsString("# Title", $content);
    }

